exports.handler = async function(event) {
  var symbol = (event.queryStringParameters && event.queryStringParameters.symbol || "CRDB").toUpperCase();
  var from   =  event.queryStringParameters && event.queryStringParameters.from || "2018-06-19";

  var lookup = BANK_PRICES[symbol];

  if (lookup) {
    var result = Object.keys(lookup)
      .filter(function(d) { return d >= from; })
      .sort()
      .map(function(d) { return { date: d, price: lookup[d] }; });

    if (result.length >= 5) return respond(result);
  }

  return { statusCode: 404, body: JSON.stringify({ error: "No data for " + symbol }) };
};

function respond(data) {
  return {
    statusCode: 200,
    headers: {
      "Content-Type": "application/json",
      "Access-Control-Allow-Origin": "*",
      "Cache-Control": "public, max-age=3600",
    },
    body: JSON.stringify(data),
  };
}
